#include<bits/stdc++.h>
using namespace std;
int a[10000001];
int main()
{
	//freopen("jinjin","r",stdin);
	//freopen("jinjin","w",stdout);
	int n,m,l,s=1,cnt,ans,j=1;
	scanf("%d%d%d",&n,&m,&l);
	if(l>=n)
	{
		printf("1");
		return 0;
	}
	for(int i=1;i<=m;i++)
	{
		scanf("%d",&a[i]);
	}
	cnt=1;
	if(l>=a[2])
		s=1;
	else
		s=2;
	for(int i=cnt;i<=m;i++)
	{
		for(j=m;j>=i+1;j--)
		{
			if(a[i]+l>=a[j])
			{
				s++;
				cnt=j;
			}
			if(cnt==m)
			{
				printf("%d",s);
				return 0;
			}
		}
	}
}
